package com.example.movie_ticket_app;

import android.content.Intent;
import android.os.Bundle;
import android.text.TextUtils;
import android.widget.Button;
import android.widget.TextView;
import android.widget.Toast;
import androidx.appcompat.app.AppCompatActivity;
import com.google.android.material.textfield.TextInputEditText;
import com.google.firebase.auth.FirebaseAuth;

public class LoginActivity extends AppCompatActivity {

    private TextInputEditText emailEditText, passwordEditText;
    private Button loginButton;
    private TextView registerText;
    private FirebaseAuth mAuth;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_login);

        mAuth = FirebaseAuth.getInstance();

        emailEditText = findViewById(R.id.email_edit_text);
        passwordEditText = findViewById(R.id.password_edit_text);
        loginButton = findViewById(R.id.login_button);
        registerText = findViewById(R.id.register_text);

        loginButton.setOnClickListener(v -> loginUser());

        registerText.setOnClickListener(v -> {
            startActivity(new Intent(LoginActivity.this, RegisterActivity.class));
        });
    }

    private void loginUser() {
        String email = emailEditText.getText().toString().trim();
        String password = passwordEditText.getText().toString().trim();

        if (TextUtils.isEmpty(email)) {
            emailEditText.setError("Email is required");
            return;
        }

        if (TextUtils.isEmpty(password)) {
            passwordEditText.setError("Password is required");
            return;
        }

        mAuth.signInWithEmailAndPassword(email, password)
                .addOnCompleteListener(this, task -> {
                    if (task.isSuccessful()) {
                        startActivity(new Intent(LoginActivity.this, MainActivity.class));
                        finish();
                    } else {
                        Toast.makeText(LoginActivity.this, "Authentication failed.", Toast.LENGTH_SHORT).show();
                    }
                });
    }
}

package com.example.movie_ticket_app;

import android.content.Intent;
import android.os.Bundle;
import android.os.Handler;
import android.os.Looper;
import android.text.TextUtils;
import android.widget.Button;
import android.widget.TextView;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;

import com.google.android.material.textfield.TextInputEditText;
import com.google.firebase.auth.FirebaseAuth;

public class LoginActivity extends AppCompatActivity {

    private TextInputEditText emailEditText, passwordEditText;
    private FirebaseAuth mAuth;
    private final Handler uiHandler = new Handler(Looper.getMainLooper());

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_login);

        mAuth = FirebaseAuth.getInstance();

        emailEditText = findViewById(R.id.email_edit_text);
        passwordEditText = findViewById(R.id.password_edit_text);
        Button loginButton = findViewById(R.id.login_button);
        TextView registerText = findViewById(R.id.register_text);

        loginButton.setOnClickListener(v -> loginUser());
        registerText.setOnClickListener(v -> startActivity(new Intent(this, RegisterActivity.class)));
    }

    @Override
    protected void onStart() {
        super.onStart();
        if (mAuth.getCurrentUser() != null) {
            startActivity(new Intent(this, MainActivity.class));
            finish();
        }
    }

    private void loginUser() {
        String email = String.valueOf(emailEditText.getText()).trim();
        String password = String.valueOf(passwordEditText.getText()).trim();

        if (TextUtils.isEmpty(email)) {
            emailEditText.setError(getString(R.string.error_email_required));
            emailEditText.requestFocus();
            return;
        }

        if (TextUtils.isEmpty(password)) {
            passwordEditText.setError(getString(R.string.error_password_required));
            passwordEditText.requestFocus();
            return;
        }

        mAuth.signInWithEmailAndPassword(email, password)
                .addOnCompleteListener(this, task -> {
                    if (task.isSuccessful()) {
                        Toast.makeText(this, getString(R.string.auth_login_success), Toast.LENGTH_SHORT).show();
                        // Delay slightly so users can see the success message before navigation.
                        uiHandler.postDelayed(this::openMainScreen, 500);
                    } else {
                        String message = task.getException() != null
                                ? task.getException().getMessage()
                                : getString(R.string.auth_login_failed);
                        Toast.makeText(this, message, Toast.LENGTH_SHORT).show();
                    }
                });
    }

    private void openMainScreen() {
        Intent intent = new Intent(this, MainActivity.class);
        intent.setFlags(Intent.FLAG_ACTIVITY_NEW_TASK | Intent.FLAG_ACTIVITY_CLEAR_TASK);
        startActivity(intent);
        finish();
    }
}

package com.example.movie_ticket_app;

import android.content.Intent;
import android.os.Bundle;
import android.text.TextUtils;
import android.widget.Button;
import android.widget.TextView;
import android.widget.Toast;
import androidx.appcompat.app.AppCompatActivity;
import com.example.movie_ticket_app.models.User;
import com.google.android.material.textfield.TextInputEditText;
import com.google.firebase.auth.FirebaseAuth;
import com.google.firebase.database.DatabaseReference;
import com.google.firebase.database.FirebaseDatabase;

public class RegisterActivity extends AppCompatActivity {

    private TextInputEditText nameEditText, emailEditText, passwordEditText;
    private Button registerButton;
    private TextView loginText;
    private FirebaseAuth mAuth;
    private DatabaseReference mDatabase;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_register);

        mAuth = FirebaseAuth.getInstance();
        mDatabase = FirebaseDatabase.getInstance().getReference();

        nameEditText = findViewById(R.id.name_edit_text);
        emailEditText = findViewById(R.id.email_edit_text);
        passwordEditText = findViewById(R.id.password_edit_text);
        registerButton = findViewById(R.id.register_button);
        loginText = findViewById(R.id.login_text);

        registerButton.setOnClickListener(v -> registerUser());

        loginText.setOnClickListener(v -> {
            finish();
        });
    }

    private void registerUser() {
        String name = nameEditText.getText().toString().trim();
        String email = emailEditText.getText().toString().trim();
        String password = passwordEditText.getText().toString().trim();

        if (TextUtils.isEmpty(name)) {
            nameEditText.setError("Name is required");
            return;
        }

        if (TextUtils.isEmpty(email)) {
            emailEditText.setError("Email is required");
            return;
        }

        if (TextUtils.isEmpty(password)) {
            passwordEditText.setError("Password is required");
            return;
        }

        mAuth.createUserWithEmailAndPassword(email, password)
                .addOnCompleteListener(this, task -> {
                    if (task.isSuccessful()) {
                        String userId = mAuth.getCurrentUser().getUid();
                        User user = new User(userId, email, name);
                        mDatabase.child("users").child(userId).setValue(user)
                                .addOnCompleteListener(dbTask -> {
                                    if (dbTask.isSuccessful()) {
                                        startActivity(new Intent(RegisterActivity.this, MainActivity.class));
                                        finish();
                                    } else {
                                        Toast.makeText(RegisterActivity.this, "Failed to save user data.", Toast.LENGTH_SHORT).show();
                                    }
                                });
                    } else {
                        Toast.makeText(RegisterActivity.this, "Registration failed: " + task.getException().getMessage(), Toast.LENGTH_SHORT).show();
                    }
                });
    }
}

package com.example.movie_ticket_app;

import android.content.Intent;
import android.os.Bundle;
import android.os.Handler;
import android.os.Looper;
import android.text.TextUtils;
import android.widget.Button;
import android.widget.TextView;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;

import com.example.movie_ticket_app.data.FirebasePaths;
import com.example.movie_ticket_app.models.User;
import com.google.android.material.textfield.TextInputEditText;
import com.google.firebase.auth.FirebaseAuth;
import com.google.firebase.auth.FirebaseUser;
import com.google.firebase.auth.UserProfileChangeRequest;
import com.google.firebase.database.DatabaseReference;
import com.google.firebase.database.FirebaseDatabase;

public class RegisterActivity extends AppCompatActivity {

    private TextInputEditText nameEditText, emailEditText, passwordEditText;
    private FirebaseAuth mAuth;
    private DatabaseReference mDatabase;
    private final Handler uiHandler = new Handler(Looper.getMainLooper());

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_register);

        mAuth = FirebaseAuth.getInstance();
        mDatabase = FirebaseDatabase.getInstance().getReference();

        nameEditText = findViewById(R.id.name_edit_text);
        emailEditText = findViewById(R.id.email_edit_text);
        passwordEditText = findViewById(R.id.password_edit_text);
        Button registerButton = findViewById(R.id.register_button);
        TextView loginText = findViewById(R.id.login_text);

        registerButton.setOnClickListener(v -> registerUser());
        loginText.setOnClickListener(v -> finish());
    }

    private void registerUser() {
        String name = String.valueOf(nameEditText.getText()).trim();
        String email = String.valueOf(emailEditText.getText()).trim();
        String password = String.valueOf(passwordEditText.getText()).trim();

        if (TextUtils.isEmpty(name)) {
            nameEditText.setError(getString(R.string.error_name_required));
            nameEditText.requestFocus();
            return;
        }

        if (TextUtils.isEmpty(email)) {
            emailEditText.setError(getString(R.string.error_email_required));
            emailEditText.requestFocus();
            return;
        }

        if (TextUtils.isEmpty(password)) {
            passwordEditText.setError(getString(R.string.error_password_required));
            passwordEditText.requestFocus();
            return;
        }

        if (password.length() < 6) {
            passwordEditText.setError(getString(R.string.error_password_min_length));
            passwordEditText.requestFocus();
            return;
        }

        mAuth.createUserWithEmailAndPassword(email, password)
                .addOnCompleteListener(this, task -> {
                    if (!task.isSuccessful() || mAuth.getCurrentUser() == null) {
                        String message = task.getException() != null
                                ? task.getException().getMessage()
                                : getString(R.string.auth_register_failed);
                        Toast.makeText(this, message, Toast.LENGTH_SHORT).show();
                        return;
                    }

                    FirebaseUser firebaseUser = mAuth.getCurrentUser();
                    String userId = firebaseUser.getUid();

                    UserProfileChangeRequest profileUpdate = new UserProfileChangeRequest.Builder()
                            .setDisplayName(name)
                            .build();

                    firebaseUser.updateProfile(profileUpdate).addOnCompleteListener(profileTask -> {
                        if (!profileTask.isSuccessful()) {
                            Toast.makeText(this, getString(R.string.auth_profile_update_failed), Toast.LENGTH_SHORT).show();
                        }

                        User user = new User(userId, email, name);
                        mDatabase.child(FirebasePaths.USERS).child(userId).setValue(user)
                                .addOnCompleteListener(dbTask -> {
                                    if (dbTask.isSuccessful()) {
                                        Toast.makeText(this, getString(R.string.auth_register_success), Toast.LENGTH_SHORT).show();
                                        // Delay slightly so users can read the result before entering the app.
                                        uiHandler.postDelayed(this::openMainScreen, 500);
                                    } else {
                                        String dbMessage = dbTask.getException() != null
                                                ? dbTask.getException().getMessage()
                                                : getString(R.string.auth_profile_sync_failed);
                                        Toast.makeText(this, dbMessage, Toast.LENGTH_SHORT).show();
                                    }
                                });
                    });
                });
    }

    private void openMainScreen() {
        Intent intent = new Intent(this, MainActivity.class);
        intent.setFlags(Intent.FLAG_ACTIVITY_NEW_TASK | Intent.FLAG_ACTIVITY_CLEAR_TASK);
        startActivity(intent);
        finish();
    }
}

package com.example.movie_ticket_app.adapters;

import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import android.widget.TextView;
import androidx.annotation.NonNull;
import androidx.recyclerview.widget.RecyclerView;
import com.example.movie_ticket_app.R;
import com.example.movie_ticket_app.models.Showtime;
import java.util.List;

public class GlobalShowtimeAdapter extends RecyclerView.Adapter<GlobalShowtimeAdapter.ViewHolder> {

    private List<Showtime> showtimeList;

    public GlobalShowtimeAdapter(List<Showtime> showtimeList) {
        this.showtimeList = showtimeList;
    }

    @NonNull
    @Override
    public ViewHolder onCreateViewHolder(@NonNull ViewGroup parent, int viewType) {
        View view = LayoutInflater.from(parent.getContext()).inflate(R.layout.item_global_showtime, parent, false);
        return new ViewHolder(view);
    }

    @Override
    public void onBindViewHolder(@NonNull ViewHolder holder, int position) {
        Showtime showtime = showtimeList.get(position);
        // In a real app, you'd fetch movie/theater names based on IDs
        // For demo, we'll use placeholder text or extend Showtime model
        holder.movieTitle.setText("Movie ID: " + showtime.getMovieId());
        holder.theaterName.setText("Theater ID: " + showtime.getTheaterId());
        holder.time.setText(showtime.getTime());
        holder.price.setText("$" + showtime.getPrice());
    }

    @Override
    public int getItemCount() {
        return showtimeList.size();
    }

    static class ViewHolder extends RecyclerView.ViewHolder {
        TextView movieTitle, theaterName, time, price;

        public ViewHolder(@NonNull View itemView) {
            super(itemView);
            movieTitle = itemView.findViewById(R.id.gs_movie_title);
            theaterName = itemView.findViewById(R.id.gs_theater_name);
            time = itemView.findViewById(R.id.gs_time);
            price = itemView.findViewById(R.id.gs_price);
        }
    }
}

package com.example.movie_ticket_app.adapters;

import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import android.widget.TextView;
import androidx.annotation.NonNull;
import androidx.recyclerview.widget.RecyclerView;
import com.example.movie_ticket_app.R;
import com.example.movie_ticket_app.models.Showtime;

import java.util.Locale;
import java.util.List;

public class GlobalShowtimeAdapter extends RecyclerView.Adapter<GlobalShowtimeAdapter.ViewHolder> {

    private List<Showtime> showtimeList;

    public GlobalShowtimeAdapter(List<Showtime> showtimeList) {
        this.showtimeList = showtimeList;
    }

    @NonNull
    @Override
    public ViewHolder onCreateViewHolder(@NonNull ViewGroup parent, int viewType) {
        View view = LayoutInflater.from(parent.getContext()).inflate(R.layout.item_global_showtime, parent, false);
        return new ViewHolder(view);
    }

    @Override
    public void onBindViewHolder(@NonNull ViewHolder holder, int position) {
        Showtime showtime = showtimeList.get(position);
        holder.movieTitle.setText(showtime.getMovieTitle() == null ? "Unknown movie" : showtime.getMovieTitle());
        holder.theaterName.setText(showtime.getTheaterName() == null ? "Unknown theater" : showtime.getTheaterName());
        holder.time.setText(showtime.getTime());
        holder.price.setText(String.format(Locale.getDefault(), "$%.2f", showtime.getPrice()));
    }

    @Override
    public int getItemCount() {
        return showtimeList.size();
    }

    static class ViewHolder extends RecyclerView.ViewHolder {
        TextView movieTitle, theaterName, time, price;

        public ViewHolder(@NonNull View itemView) {
            super(itemView);
            movieTitle = itemView.findViewById(R.id.gs_movie_title);
            theaterName = itemView.findViewById(R.id.gs_theater_name);
            time = itemView.findViewById(R.id.gs_time);
            price = itemView.findViewById(R.id.gs_price);
        }
    }
}

package com.example.movie_ticket_app.data;

import com.example.movie_ticket_app.models.Movie;
import com.example.movie_ticket_app.models.Showtime;
import com.example.movie_ticket_app.models.Theater;
import com.google.firebase.database.DatabaseReference;
import com.google.firebase.database.FirebaseDatabase;

import java.util.Calendar;
import java.util.HashMap;
import java.util.Locale;
import java.util.Map;

public final class SampleDataSeeder {
    private static final long SEED_VERSION = 1L;

    private SampleDataSeeder() {
    }

    public static void seedIfNeeded() {
        DatabaseReference rootRef = FirebaseDatabase.getInstance().getReference();
        rootRef.child("seedVersion").get().addOnSuccessListener(snapshot -> {
            Long currentVersion = snapshot.getValue(Long.class);
            if (currentVersion != null && currentVersion >= SEED_VERSION) {
                return;
            }

            Map<String, Object> updates = new HashMap<>();
            seedMovies(updates);
            seedTheaters(updates);
            seedShowtimes(updates);
            updates.put("seedVersion", SEED_VERSION);
            rootRef.updateChildren(updates);
        });
    }

    private static void seedMovies(Map<String, Object> updates) {
        Movie avatar = new Movie("m1", "Avatar: The Way of Water",
                "Jake Sully and his family face a powerful threat and fight to protect Pandora.",
                "https://image.tmdb.org/t/p/w500/t6HIqrRAclMCA60NsSmeqe9RmNV.jpg",
                "Sci-Fi", 7.8, 192);

        Movie wick = new Movie("m2", "John Wick: Chapter 4",
                "John Wick uncovers a path to defeating The High Table.",
                "https://image.tmdb.org/t/p/w500/vZloFAK7NmvMGKE7VkF5UHaz0I.jpg",
                "Action", 8.1, 169);

        Movie spider = new Movie("m3", "Spider-Man: Across the Spider-Verse",
                "Miles Morales catapults across the Multiverse and meets new Spider allies.",
                "https://image.tmdb.org/t/p/w500/8Vt6mWEReuy4Of61Lnj5Xj704m8.jpg",
                "Animation", 8.6, 140);

        updates.put(FirebasePaths.MOVIES + "/" + avatar.getId(), avatar);
        updates.put(FirebasePaths.MOVIES + "/" + wick.getId(), wick);
        updates.put(FirebasePaths.MOVIES + "/" + spider.getId(), spider);
    }

    private static void seedTheaters(Map<String, Object> updates) {
        Theater t1 = new Theater("t1", "Cineplex Central", "123 Movie St, Cinema City");
        Theater t2 = new Theater("t2", "Starlight Cinema", "456 Star Blvd, Galaxy Town");
        Theater t3 = new Theater("t3", "Grand Theater", "789 Main Ave, Downtown");

        updates.put(FirebasePaths.THEATERS + "/" + t1.getId(), t1);
        updates.put(FirebasePaths.THEATERS + "/" + t2.getId(), t2);
        updates.put(FirebasePaths.THEATERS + "/" + t3.getId(), t3);
    }

    private static void seedShowtimes(Map<String, Object> updates) {
        addShowtime(updates, "s1", "m1", "Avatar: The Way of Water", "t1", "Cineplex Central", 10, 0, 12.5);
        addShowtime(updates, "s2", "m1", "Avatar: The Way of Water", "t2", "Starlight Cinema", 19, 30, 15.0);
        addShowtime(updates, "s3", "m2", "John Wick: Chapter 4", "t1", "Cineplex Central", 16, 0, 13.0);
        addShowtime(updates, "s4", "m2", "John Wick: Chapter 4", "t3", "Grand Theater", 21, 0, 15.5);
        addShowtime(updates, "s5", "m3", "Spider-Man: Across the Spider-Verse", "t2", "Starlight Cinema", 14, 15, 11.0);
        addShowtime(updates, "s6", "m3", "Spider-Man: Across the Spider-Verse", "t3", "Grand Theater", 18, 45, 12.0);
    }

    private static void addShowtime(Map<String, Object> updates, String id, String movieId, String movieTitle,
                                    String theaterId, String theaterName, int hour, int minute, double price) {
        long startAt = millisTodayOrTomorrow(hour, minute);
        String displayTime = String.format(Locale.getDefault(), "%02d:%02d", hour, minute);

        Showtime showtime = new Showtime(id, movieId, theaterId, displayTime, price);
        showtime.setMovieTitle(movieTitle);
        showtime.setTheaterName(theaterName);
        showtime.setStartTimeMillis(startAt);

        updates.put(FirebasePaths.SHOWTIMES + "/" + id, showtime);
    }

    private static long millisTodayOrTomorrow(int hour, int minute) {
        Calendar now = Calendar.getInstance();
        Calendar scheduled = Calendar.getInstance();
        scheduled.set(Calendar.HOUR_OF_DAY, hour);
        scheduled.set(Calendar.MINUTE, minute);
        scheduled.set(Calendar.SECOND, 0);
        scheduled.set(Calendar.MILLISECOND, 0);

        if (scheduled.before(now)) {
            scheduled.add(Calendar.DAY_OF_YEAR, 1);
        }
        return scheduled.getTimeInMillis();
    }
}

package com.example.movie_ticket_app.fragments;

import android.content.Intent;
import android.os.Bundle;
import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import androidx.annotation.NonNull;
import androidx.annotation.Nullable;
import androidx.fragment.app.Fragment;
import androidx.recyclerview.widget.GridLayoutManager;
import androidx.recyclerview.widget.RecyclerView;
import com.example.movie_ticket_app.MovieDetailsActivity;
import com.example.movie_ticket_app.R;
import com.example.movie_ticket_app.adapters.MovieAdapter;
import com.example.movie_ticket_app.models.Movie;
import java.util.ArrayList;
import java.util.List;

public class MoviesFragment extends Fragment {

    private RecyclerView recyclerView;
    private MovieAdapter adapter;
    private List<Movie> movieList;

    @Nullable
    @Override
    public View onCreateView(@NonNull LayoutInflater inflater, @Nullable ViewGroup container, @Nullable Bundle savedInstanceState) {
        View view = inflater.inflate(R.layout.fragment_movies, container, false);

        recyclerView = view.findViewById(R.id.recycler_movies);
        recyclerView.setLayoutManager(new GridLayoutManager(getContext(), 2));

        movieList = new ArrayList<>();
        // Adding dummy data for demonstration
        movieList.add(new Movie("1", "Avatar: The Way of Water", "Jake Sully lives with his newfound family formed on the extrasolar moon Pandora.", "https://image.tmdb.org/t/p/w500/t6EeGiS1Yja0DVZpZq1w0vN3qyR.jpg", "Sci-Fi", 7.8, 192));
        movieList.add(new Movie("2", "John Wick: Chapter 4", "John Wick uncovers a path to defeating The High Table.", "https://image.tmdb.org/t/p/w500/vZloY0Cc8p7Mvst34vYn3vS2S9H.jpg", "Action", 8.2, 169));
        movieList.add(new Movie("3", "Spider-Man: Across the Spider-Verse", "Miles Morales catapults across the Multiverse.", "https://image.tmdb.org/t/p/w500/8VtB9m93Sj18j6rqvfuBPyz9C6w.jpg", "Animation", 8.9, 140));

        adapter = new MovieAdapter(movieList, movie -> {
            Intent intent = new Intent(getContext(), MovieDetailsActivity.class);
            intent.putExtra("movie_title", movie.getTitle());
            startActivity(intent);
        });
        recyclerView.setAdapter(adapter);

        return view;
    }
}

package com.example.movie_ticket_app.fragments;

import android.content.Intent;
import android.os.Bundle;
import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import android.widget.TextView;

import androidx.annotation.NonNull;
import androidx.annotation.Nullable;
import androidx.fragment.app.Fragment;
import androidx.recyclerview.widget.GridLayoutManager;
import androidx.recyclerview.widget.RecyclerView;

import com.example.movie_ticket_app.MovieDetailsActivity;
import com.example.movie_ticket_app.R;
import com.example.movie_ticket_app.adapters.MovieAdapter;
import com.example.movie_ticket_app.data.FirebasePaths;
import com.example.movie_ticket_app.models.Movie;
import com.google.firebase.database.DataSnapshot;
import com.google.firebase.database.FirebaseDatabase;

import java.util.ArrayList;
import java.util.List;

public class MoviesFragment extends Fragment {

    private final List<Movie> movieList = new ArrayList<>();
    private MovieAdapter adapter;
    private TextView emptyState;

    @Nullable
    @Override
    public View onCreateView(@NonNull LayoutInflater inflater, @Nullable ViewGroup container,
                             @Nullable Bundle savedInstanceState) {
        View view = inflater.inflate(R.layout.fragment_movies, container, false);

        RecyclerView recyclerView = view.findViewById(R.id.recycler_movies);
        emptyState = view.findViewById(R.id.text_empty_movies);
        recyclerView.setLayoutManager(new GridLayoutManager(getContext(), 2));

        adapter = new MovieAdapter(movieList, movie -> {
            Intent intent = new Intent(getContext(), MovieDetailsActivity.class);
            intent.putExtra("movie_id", movie.getId());
            intent.putExtra("movie_title", movie.getTitle());
            intent.putExtra("movie_description", movie.getDescription());
            intent.putExtra("movie_genre", movie.getGenre());
            intent.putExtra("movie_rating", movie.getRating());
            intent.putExtra("movie_poster", movie.getPosterUrl());
            startActivity(intent);
        });
        recyclerView.setAdapter(adapter);

        loadMovies();
        return view;
    }

    private void loadMovies() {
        FirebaseDatabase.getInstance().getReference()
                .child(FirebasePaths.MOVIES)
                .get()
                .addOnSuccessListener(this::bindMovies)
                .addOnFailureListener(e -> emptyState.setVisibility(View.VISIBLE));
    }

    private void bindMovies(DataSnapshot snapshot) {
        movieList.clear();
        for (DataSnapshot child : snapshot.getChildren()) {
            Movie movie = child.getValue(Movie.class);
            if (movie != null) {
                movieList.add(movie);
            }
        }

        adapter.notifyDataSetChanged();
        emptyState.setVisibility(movieList.isEmpty() ? View.VISIBLE : View.GONE);
    }
}

package com.example.movie_ticket_app.fragments;

import android.content.Intent;
import android.os.Bundle;
import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import android.widget.TextView;
import androidx.annotation.NonNull;
import androidx.annotation.Nullable;
import androidx.fragment.app.Fragment;
import com.example.movie_ticket_app.LoginActivity;
import com.example.movie_ticket_app.R;
import com.google.android.material.button.MaterialButton;
import com.google.firebase.auth.FirebaseAuth;
import com.google.firebase.auth.FirebaseUser;
import com.google.firebase.database.DataSnapshot;
import com.google.firebase.database.DatabaseError;
import com.google.firebase.database.DatabaseReference;
import com.google.firebase.database.FirebaseDatabase;
import com.google.firebase.database.ValueEventListener;

public class ProfileFragment extends Fragment {

    private TextView nameText, emailText;
    private MaterialButton logoutBtn;
    private FirebaseAuth mAuth;
    private DatabaseReference mDatabase;

    @Nullable
    @Override
    public View onCreateView(@NonNull LayoutInflater inflater, @Nullable ViewGroup container, @Nullable Bundle savedInstanceState) {
        View view = inflater.inflate(R.layout.fragment_profile, container, false);

        nameText = view.findViewById(R.id.profile_name);
        emailText = view.findViewById(R.id.profile_email);
        logoutBtn = view.findViewById(R.id.btn_logout);

        mAuth = FirebaseAuth.getInstance();
        FirebaseUser user = mAuth.getCurrentUser();

        if (user != null) {
            emailText.setText(user.getEmail());
            mDatabase = FirebaseDatabase.getInstance().getReference().child("users").child(user.getUid());
            mDatabase.addValueEventListener(new ValueEventListener() {
                @Override
                public void onDataChange(@NonNull DataSnapshot snapshot) {
                    if (snapshot.exists()) {
                        String name = snapshot.child("fullName").getValue(String.class);
                        nameText.setText(name);
                    }
                }

                @Override
                public void onCancelled(@NonNull DatabaseError error) {
                }
            });
        }

        logoutBtn.setOnClickListener(v -> {
            mAuth.signOut();
            Intent intent = new Intent(getActivity(), LoginActivity.class);
            intent.setFlags(Intent.FLAG_ACTIVITY_NEW_TASK | Intent.FLAG_ACTIVITY_CLEAR_TASK);
            startActivity(intent);
        });

        return view;
    }
}

package com.example.movie_ticket_app.fragments;

import android.content.Intent;
import android.os.Bundle;
import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import android.widget.TextView;
import androidx.annotation.NonNull;
import androidx.annotation.Nullable;
import androidx.fragment.app.Fragment;
import com.example.movie_ticket_app.LoginActivity;
import com.example.movie_ticket_app.R;
import com.example.movie_ticket_app.data.FirebasePaths;
import com.google.android.material.button.MaterialButton;
import com.google.firebase.auth.FirebaseAuth;
import com.google.firebase.auth.FirebaseUser;
import com.google.firebase.database.DataSnapshot;
import com.google.firebase.database.DatabaseError;
import com.google.firebase.database.DatabaseReference;
import com.google.firebase.database.FirebaseDatabase;
import com.google.firebase.database.ValueEventListener;

public class ProfileFragment extends Fragment {

    @Nullable
    @Override
    public View onCreateView(@NonNull LayoutInflater inflater, @Nullable ViewGroup container, @Nullable Bundle savedInstanceState) {
        View view = inflater.inflate(R.layout.fragment_profile, container, false);

        TextView nameText = view.findViewById(R.id.profile_name);
        TextView emailText = view.findViewById(R.id.profile_email);
        MaterialButton logoutBtn = view.findViewById(R.id.btn_logout);

        FirebaseAuth mAuth = FirebaseAuth.getInstance();
        FirebaseUser user = mAuth.getCurrentUser();
        DatabaseReference mDatabase;

        if (user != null) {
            emailText.setText(user.getEmail());
            nameText.setText(resolveFallbackName(user));
            mDatabase = FirebaseDatabase.getInstance().getReference().child(FirebasePaths.USERS).child(user.getUid());
            mDatabase.addValueEventListener(new ValueEventListener() {
                @Override
                public void onDataChange(@NonNull DataSnapshot snapshot) {
                    if (snapshot.exists()) {
                        String name = snapshot.child("fullName").getValue(String.class);
                        if (name != null && !name.trim().isEmpty()) {
                            nameText.setText(name);
                        } else {
                            nameText.setText(resolveFallbackName(user));
                        }
                    } else {
                        nameText.setText(resolveFallbackName(user));
                    }
                }

                @Override
                public void onCancelled(@NonNull DatabaseError error) {
                }
            });
        }

        logoutBtn.setOnClickListener(v -> {
            mAuth.signOut();
            Intent intent = new Intent(getActivity(), LoginActivity.class);
            intent.setFlags(Intent.FLAG_ACTIVITY_NEW_TASK | Intent.FLAG_ACTIVITY_CLEAR_TASK);
            startActivity(intent);
        });

        return view;
    }

    private String resolveFallbackName(FirebaseUser user) {
        String displayName = user.getDisplayName();
        if (displayName != null && !displayName.trim().isEmpty()) {
            return displayName;
        }

        String email = user.getEmail();
        if (email != null) {
            int separator = email.indexOf('@');
            if (separator > 0) {
                return email.substring(0, separator);
            }
            if (!email.trim().isEmpty()) {
                return email;
            }
        }

        return "Movie Fan";
    }
}

package com.example.movie_ticket_app.fragments;

import android.os.Bundle;
import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import android.widget.TextView;

import androidx.annotation.NonNull;
import androidx.annotation.Nullable;
import androidx.fragment.app.Fragment;
import androidx.recyclerview.widget.LinearLayoutManager;
import androidx.recyclerview.widget.RecyclerView;

import com.example.movie_ticket_app.R;
import com.example.movie_ticket_app.adapters.GlobalShowtimeAdapter;
import com.example.movie_ticket_app.data.FirebasePaths;
import com.example.movie_ticket_app.models.Showtime;
import com.google.firebase.database.DataSnapshot;
import com.google.firebase.database.FirebaseDatabase;

import java.util.ArrayList;
import java.util.Comparator;
import java.util.List;

public class ShowtimesFragment extends Fragment {
    private final List<Showtime> showtimeList = new ArrayList<>();
    private GlobalShowtimeAdapter adapter;
    private TextView emptyState;

    @Nullable
    @Override
    public View onCreateView(@NonNull LayoutInflater inflater, @Nullable ViewGroup container,
                             @Nullable Bundle savedInstanceState) {
        View view = inflater.inflate(R.layout.fragment_showtimes, container, false);

        RecyclerView recyclerView = view.findViewById(R.id.recycler_all_showtimes);
        emptyState = view.findViewById(R.id.text_empty_showtimes);
        recyclerView.setLayoutManager(new LinearLayoutManager(getContext()));

        adapter = new GlobalShowtimeAdapter(showtimeList);
        recyclerView.setAdapter(adapter);

        loadShowtimes();
        return view;
    }

    private void loadShowtimes() {
        FirebaseDatabase.getInstance().getReference()
                .child(FirebasePaths.SHOWTIMES)
                .get()
                .addOnSuccessListener(this::bindShowtimes)
                .addOnFailureListener(e -> emptyState.setVisibility(View.VISIBLE));
    }

    private void bindShowtimes(DataSnapshot snapshot) {
        showtimeList.clear();
        for (DataSnapshot child : snapshot.getChildren()) {
            Showtime showtime = child.getValue(Showtime.class);
            if (showtime != null) {
                showtimeList.add(showtime);
            }
        }

        showtimeList.sort(Comparator.comparingLong(Showtime::getStartTimeMillis));
        adapter.notifyDataSetChanged();
        emptyState.setVisibility(showtimeList.isEmpty() ? View.VISIBLE : View.GONE);
    }
}

