package com.example.movie_ticket_app.fragments;

import android.os.Bundle;
import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import androidx.annotation.NonNull;
import androidx.annotation.Nullable;
import androidx.fragment.app.Fragment;
import androidx.recyclerview.widget.LinearLayoutManager;
import androidx.recyclerview.widget.RecyclerView;
import com.example.movie_ticket_app.R;
import com.example.movie_ticket_app.adapters.TicketAdapter;
import com.example.movie_ticket_app.models.Ticket;
import com.google.firebase.auth.FirebaseAuth;
import com.google.firebase.database.DataSnapshot;
import com.google.firebase.database.DatabaseError;
import com.google.firebase.database.DatabaseReference;
import com.google.firebase.database.FirebaseDatabase;
import com.google.firebase.database.ValueEventListener;
import java.util.ArrayList;
import java.util.List;

public class TicketsFragment extends Fragment {

    private RecyclerView recyclerView;
    private TicketAdapter adapter;
    private List<Ticket> ticketList;
    private DatabaseReference mDatabase;
    private FirebaseAuth mAuth;

    @Nullable
    @Override
    public View onCreateView(@NonNull LayoutInflater inflater, @Nullable ViewGroup container, @Nullable Bundle savedInstanceState) {
        View view = inflater.inflate(R.layout.fragment_movies, container, false); // Reuse fragment_movies for list

        recyclerView = view.findViewById(R.id.recycler_movies);
        recyclerView.setLayoutManager(new LinearLayoutManager(getContext()));

        ticketList = new ArrayList<>();
        adapter = new TicketAdapter(ticketList);
        recyclerView.setAdapter(adapter);

        mAuth = FirebaseAuth.getInstance();
        mDatabase = FirebaseDatabase.getInstance().getReference().child("tickets");

        if (mAuth.getCurrentUser() != null) {
            String userId = mAuth.getCurrentUser().getUid();
            mDatabase.orderByChild("userId").equalTo(userId).addValueEventListener(new ValueEventListener() {
                @Override
                public void onDataChange(@NonNull DataSnapshot snapshot) {
                    ticketList.clear();
                    for (DataSnapshot postSnapshot : snapshot.getChildren()) {
                        Ticket ticket = postSnapshot.getValue(Ticket.class);
                        ticketList.add(ticket);
                    }
                    adapter.notifyDataSetChanged();
                }

                @Override
                public void onCancelled(@NonNull DatabaseError error) {
                }
            });
        }

        return view;
    }
}

package com.example.movie_ticket_app.fragments;

import android.os.Bundle;
import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import android.widget.TextView;

import androidx.annotation.NonNull;
import androidx.annotation.Nullable;
import androidx.fragment.app.Fragment;
import androidx.recyclerview.widget.LinearLayoutManager;
import androidx.recyclerview.widget.RecyclerView;

import com.example.movie_ticket_app.R;
import com.example.movie_ticket_app.adapters.TicketAdapter;
import com.example.movie_ticket_app.data.FirebasePaths;
import com.example.movie_ticket_app.models.Ticket;
import com.google.firebase.auth.FirebaseAuth;
import com.google.firebase.database.DataSnapshot;
import com.google.firebase.database.DatabaseError;
import com.google.firebase.database.FirebaseDatabase;
import com.google.firebase.database.ValueEventListener;

import java.util.ArrayList;
import java.util.List;

public class TicketsFragment extends Fragment {

    private final List<Ticket> ticketList = new ArrayList<>();
    private TicketAdapter adapter;
    private TextView emptyState;

    @Nullable
    @Override
    public View onCreateView(@NonNull LayoutInflater inflater, @Nullable ViewGroup container,
                             @Nullable Bundle savedInstanceState) {
        View view = inflater.inflate(R.layout.fragment_tickets, container, false);

        RecyclerView recyclerView = view.findViewById(R.id.recycler_tickets);
        emptyState = view.findViewById(R.id.text_empty_tickets);
        recyclerView.setLayoutManager(new LinearLayoutManager(getContext()));

        adapter = new TicketAdapter(ticketList);
        recyclerView.setAdapter(adapter);

        loadTickets();
        return view;
    }

    private void loadTickets() {
        if (FirebaseAuth.getInstance().getCurrentUser() == null) {
            emptyState.setVisibility(View.VISIBLE);
            return;
        }

        String userId = FirebaseAuth.getInstance().getCurrentUser().getUid();
        FirebaseDatabase.getInstance().getReference()
                .child(FirebasePaths.TICKETS)
                .orderByChild("userId")
                .equalTo(userId)
                .addValueEventListener(new ValueEventListener() {
                    @Override
                    public void onDataChange(@NonNull DataSnapshot snapshot) {
                        ticketList.clear();
                        for (DataSnapshot child : snapshot.getChildren()) {
                            Ticket ticket = child.getValue(Ticket.class);
                            if (ticket != null) {
                                ticketList.add(ticket);
                            }
                        }
                        adapter.notifyDataSetChanged();
                        emptyState.setVisibility(ticketList.isEmpty() ? View.VISIBLE : View.GONE);
                    }

                    @Override
                    public void onCancelled(@NonNull DatabaseError error) {
                        emptyState.setVisibility(View.VISIBLE);
                    }
                });
    }
}

package com.example.movie_ticket_app.models;

public class Showtime {
    private String id;
    private String movieId;
    private String theaterId;
    private String time;
    private double price;

    public Showtime() {}

    public Showtime(String id, String movieId, String theaterId, String time, double price) {
        this.id = id;
        this.movieId = movieId;
        this.theaterId = theaterId;
        this.time = time;
        this.price = price;
    }

    public String getId() { return id; }
    public String getMovieId() { return movieId; }
    public String getTheaterId() { return theaterId; }
    public String getTime() { return time; }
    public double getPrice() { return price; }
}

package com.example.movie_ticket_app.models;

public class Showtime {
    private String id;
    private String movieId;
    private String theaterId;
    private String time;
    private double price;
    private String movieTitle;
    private String theaterName;
    private long startTimeMillis;

    public Showtime() {}

    public Showtime(String id, String movieId, String theaterId, String time, double price) {
        this.id = id;
        this.movieId = movieId;
        this.theaterId = theaterId;
        this.time = time;
        this.price = price;
    }

    public String getId() { return id; }
    public String getMovieId() { return movieId; }
    public String getTheaterId() { return theaterId; }
    public String getTime() { return time; }
    public double getPrice() { return price; }
    public String getMovieTitle() { return movieTitle; }
    public String getTheaterName() { return theaterName; }
    public long getStartTimeMillis() { return startTimeMillis; }

    public void setMovieTitle(String movieTitle) { this.movieTitle = movieTitle; }
    public void setTheaterName(String theaterName) { this.theaterName = theaterName; }
    public void setStartTimeMillis(long startTimeMillis) { this.startTimeMillis = startTimeMillis; }
}

package com.example.movie_ticket_app.receivers;

import android.app.NotificationChannel;
import android.app.NotificationManager;
import android.app.PendingIntent;
import android.content.BroadcastReceiver;
import android.content.Context;
import android.content.Intent;
import android.os.Build;

import androidx.core.app.NotificationCompat;

import com.example.movie_ticket_app.MainActivity;
import com.example.movie_ticket_app.R;

public class ReminderBroadcastReceiver extends BroadcastReceiver {
    public static final String CHANNEL_ID = "movie_reminders";
    public static final String EXTRA_TITLE = "extra_title";
    public static final String EXTRA_MESSAGE = "extra_message";

    @Override
    public void onReceive(Context context, Intent intent) {
        NotificationManager manager = (NotificationManager) context.getSystemService(Context.NOTIFICATION_SERVICE);
        if (manager == null) {
            return;
        }

        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            NotificationChannel channel = new NotificationChannel(
                    CHANNEL_ID,
                    "Movie Reminders",
                    NotificationManager.IMPORTANCE_DEFAULT
            );
            manager.createNotificationChannel(channel);
        }

        Intent openIntent = new Intent(context, MainActivity.class);
        PendingIntent pendingIntent = PendingIntent.getActivity(
                context,
                0,
                openIntent,
                PendingIntent.FLAG_IMMUTABLE | PendingIntent.FLAG_UPDATE_CURRENT
        );

        String title = intent.getStringExtra(EXTRA_TITLE);
        String message = intent.getStringExtra(EXTRA_MESSAGE);

        NotificationCompat.Builder builder = new NotificationCompat.Builder(context, CHANNEL_ID)
                .setSmallIcon(R.mipmap.ic_launcher)
                .setContentTitle(title == null ? "Showtime Reminder" : title)
                .setContentText(message == null ? "Your movie starts soon." : message)
                .setAutoCancel(true)
                .setPriority(NotificationCompat.PRIORITY_DEFAULT)
                .setContentIntent(pendingIntent);

        manager.notify((int) System.currentTimeMillis(), builder.build());
    }
}

package com.example.movie_ticket_app.utils;

import android.app.AlarmManager;
import android.app.PendingIntent;
import android.content.Context;
import android.content.Intent;
import android.os.Build;

import com.example.movie_ticket_app.models.Ticket;
import com.example.movie_ticket_app.receivers.ReminderBroadcastReceiver;

public final class ReminderScheduler {
    private static final long REMINDER_OFFSET_MILLIS = 30 * 60 * 1000L;

    private ReminderScheduler() {
    }

    public static void schedule(Context context, Ticket ticket) {
        long showtimeMillis = ticket.getShowtimeMillis();
        if (showtimeMillis <= 0) {
            return;
        }

        long triggerAt = showtimeMillis - REMINDER_OFFSET_MILLIS;
        if (triggerAt <= System.currentTimeMillis()) {
            triggerAt = System.currentTimeMillis() + 10_000L;
        }

        AlarmManager alarmManager = (AlarmManager) context.getSystemService(Context.ALARM_SERVICE);
        if (alarmManager == null) {
            return;
        }

        Intent intent = new Intent(context, ReminderBroadcastReceiver.class);
        intent.putExtra(ReminderBroadcastReceiver.EXTRA_TITLE, "Showtime in 30 minutes");
        intent.putExtra(ReminderBroadcastReceiver.EXTRA_MESSAGE,
                ticket.getMovieTitle() + " at " + ticket.getTheaterName() + " starts soon.");

        int requestCode = ticket.getId() == null ? (int) System.currentTimeMillis() : ticket.getId().hashCode();
        PendingIntent pendingIntent = PendingIntent.getBroadcast(
                context,
                requestCode,
                intent,
                PendingIntent.FLAG_IMMUTABLE | PendingIntent.FLAG_UPDATE_CURRENT
        );

        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.M) {
            alarmManager.setAndAllowWhileIdle(AlarmManager.RTC_WAKEUP, triggerAt, pendingIntent);
        } else {
            alarmManager.set(AlarmManager.RTC_WAKEUP, triggerAt, pendingIntent);
        }
    }
}

{
  "rules": {
    ".read": false,
    ".write": false,
    "users": {
      "$uid": {
        ".read": "auth != null && auth.uid === $uid",
        ".write": "auth != null && auth.uid === $uid",
        ".validate": "newData.hasChildren(['id', 'email', 'fullName'])"
      }
    },
    "movies": {
      ".read": "auth != null",
      ".write": "auth != null"
    },
    "theaters": {
      ".read": "auth != null",
      ".write": "auth != null"
    },
    "showtimes": {
      ".read": "auth != null",
      ".write": "auth != null",
      ".indexOn": ["movieId"]
    },
    "seedVersion": {
      ".read": "auth != null",
      ".write": "auth != null"
    },
    "tickets": {
      ".indexOn": ["userId"],
      "$ticketId": {
        ".read": "auth != null && data.child('userId').val() === auth.uid",
        ".write": "auth != null && newData.child('userId').val() === auth.uid",
        ".validate": "newData.hasChildren(['id', 'userId', 'showtimeId', 'movieTitle', 'theaterName', 'time', 'seatNumber', 'price', 'showtimeMillis'])"
      }
    }
  }
}
